mapper.update:
UPDATE trip.trip_invites
SET
  status = 'REVOKED',
  revoked_at = #{revokedAt}
WHERE id = #{inviteId}
  AND status = 'PENDING'

UPDATE trip.trip_members
SET
  status = 'REMOVED',
  left_at = #{removedAt},
  removed_by_user_id = #{removedByUserId}
WHERE trip_id = #{tripId}
  AND user_id = #{userId}
  AND status = 'ACTIVE'
